import json
import os
import pymysql
import logging

logger = logging.getLogger()
logger.setLevel(logging.INFO)

# Database connection parameters from environment variables
DB_HOST = os.environ.get('DB_HOST')
DB_USER = os.environ.get('DB_USER')
DB_PASSWORD = os.environ.get('DB_PASSWORD')
DB_NAME = os.environ.get('DB_NAME')
DB_PORT = int(os.environ.get('DB_PORT', 3306))

# Whitelist of allowed search fields to prevent SQL injection via column names
ALLOWED_SEARCH_FIELDS = {
    'product_id',
    'name',
    'category',
    'brand',
    'min_price',
    'max_price',
    'description',
    'sku',
    'status',
    'min_rating',
    'max_rating',
}

# Allowed sort columns and directions
ALLOWED_SORT_COLUMNS = {
    'product_id',
    'name',
    'category',
    'brand',
    'price',
    'rating',
    'created_at',
    'updated_at',
}

ALLOWED_SORT_DIRECTIONS = {'ASC', 'DESC'}

# Maximum results to prevent excessive data retrieval
MAX_LIMIT = 100
DEFAULT_LIMIT = 20


def get_db_connection():
    """Create and return a database connection."""
    return pymysql.connect(
        host=DB_HOST,
        user=DB_USER,
        password=DB_PASSWORD,
        database=DB_NAME,
        port=DB_PORT,
        charset='utf8mb4',
        cursorclass=pymysql.cursors.DictCursor,
        connect_timeout=5,
        read_timeout=10,
        write_timeout=10,
        ssl={'ssl': True} if os.environ.get('DB_USE_SSL', 'true').lower() == 'true' else None,
    )


def build_search_query(params):
    """
    Dynamically build a parameterized SQL query based on search parameters.
    Returns a tuple of (query_string, parameter_list).
    """
    base_query = "SELECT product_id, name, category, brand, price, description, sku, status, rating, created_at, updated_at FROM products"
    conditions = []
    values = []

    if not params:
        return base_query + " LIMIT %s", [DEFAULT_LIMIT]

    # Filter out any parameters not in the allowed set
    sanitized_params = {k: v for k, v in params.items() if k in ALLOWED_SEARCH_FIELDS or k in ('sort_by', 'sort_dir', 'limit', 'offset')}

    # Exact match fields
    exact_match_fields = {'product_id', 'category', 'brand', 'sku', 'status'}
    for field in exact_match_fields:
        if field in sanitized_params and sanitized_params[field] is not None:
            value = str(sanitized_params[field]).strip()
            if value:
                conditions.append(f"`{field}` = %s")
                values.append(value)

    # LIKE search fields (partial match)
    like_fields = {'name', 'description'}
    for field in like_fields:
        if field in sanitized_params and sanitized_params[field] is not None:
            value = str(sanitized_params[field]).strip()
            if value:
                # Escape special LIKE characters in the value
                escaped_value = value.replace('\\', '\\\\').replace('%', '\\%').replace('_', '\\_')
                conditions.append(f"`{field}` LIKE %s")
                values.append(f"%{escaped_value}%")

    # Range fields for price
    if 'min_price' in sanitized_params and sanitized_params['min_price'] is not None:
        try:
            min_price = float(sanitized_params['min_price'])
            if min_price < 0:
                raise ValueError("min_price must be non-negative")
            conditions.append("`price` >= %s")
            values.append(min_price)
        except (ValueError, TypeError):
            logger.warning("Invalid min_price parameter, skipping")

    if 'max_price' in sanitized_params and sanitized_params['max_price'] is not None:
        try:
            max_price = float(sanitized_params['max_price'])
            if max_price < 0:
                raise ValueError("max_price must be non-negative")
            conditions.append("`price` <= %s")
            values.append(max_price)
        except (ValueError, TypeError):
            logger.warning("Invalid max_price parameter, skipping")

    # Range fields for rating
    if 'min_rating' in sanitized_params and sanitized_params['min_rating'] is not None:
        try:
            min_rating = float(sanitized_params['min_rating'])
            if not (0 <= min_rating <= 5):
                raise ValueError("min_rating must be between 0 and 5")
            conditions.append("`rating` >= %s")
            values.append(min_rating)
        except (ValueError, TypeError):
            logger.warning("Invalid min_rating parameter, skipping")

    if 'max_rating' in sanitized_params and sanitized_params['max_rating'] is not None:
        try:
            max_rating = float(sanitized_params['max_rating'])
            if not (0 <= max_rating <= 5):
                raise ValueError("max_rating must be between 0 and 5")
            conditions.append("`rating` <= %s")
            values.append(max_rating)
        except (ValueError, TypeError):
            logger.warning("Invalid max_rating parameter, skipping")

    # Build WHERE clause
    if conditions:
        base_query += " WHERE " + " AND ".join(conditions)

    # Sorting - validated against whitelist
    sort_by = sanitized_params.get('sort_by', 'product_id')
    sort_dir = str(sanitized_params.get('sort_dir', 'ASC')).upper()

    if sort_by not in ALLOWED_SORT_COLUMNS:
        sort_by = 'product_id'
    if sort_dir not in ALLOWED_SORT_DIRECTIONS:
        sort_dir = 'ASC'

    base_query += f" ORDER BY `{sort_by}` {sort_dir}"

    # Pagination
    try:
        limit = int(sanitized_params.get('limit', DEFAULT_LIMIT))
        limit = max(1, min(limit, MAX_LIMIT))
    except (ValueError, TypeError):
        limit = DEFAULT_LIMIT

    try:
        offset = int(sanitized_params.get('offset', 0))
        offset = max(0, offset)
    except (ValueError, TypeError):
        offset = 0

    base_query += " LIMIT %s OFFSET %s"
    values.extend([limit, offset])

    return base_query, values


def build_count_query(params):
    """
    Build a COUNT query to return total results for pagination metadata.
    Mirrors the WHERE clause of build_search_query.
    """
    # Reuse the search query builder and replace SELECT ... FROM with SELECT COUNT(*)
    search_query, values = build_search_query(params)

    # Remove LIMIT, OFFSET, and ORDER BY for count query
    # Find the ORDER BY position and truncate
    order_idx = search_query.find(" ORDER BY")
    if order_idx != -1:
        count_query_body = search_query[:order_idx]
        # Remove the limit and offset values from params
        # The last two values are always limit and offset
        count_values = values[:-2]
    else:
        count_query_body = search_query
        count_values = values

    # Replace the SELECT ... FROM with SELECT COUNT(*)
    from_idx = count_query_body.find(" FROM ")
    if from_idx != -1:
        count_query = "SELECT COUNT(*) as total" + count_query_body[from_idx:]
    else:
        count_query = "SELECT COUNT(*) as total FROM products"
        count_values = []

    return count_query, count_values


def extract_params(event):
    """
    Extract search parameters from the API Gateway event.
    Supports both query string parameters and JSON body.
    """
    params = {}

    # Extract from query string parameters
    if event.get('queryStringParameters'):
        params.update(event['queryStringParameters'])

    # Extract from multiValueQueryStringParameters if present
    if event.get('multiValueQueryStringParameters'):
        for key, value_list in event['multiValueQueryStringParameters'].items():
            if len(value_list) == 1:
                params[key] = value_list[0]
            # For multi-value, take the first one (or handle as needed)

    # Extract from body (POST requests)
    if event.get('body'):
        try:
            body = event['body']
            if isinstance(body, str):
                body = json.loads(body)
            if isinstance(body, dict):
                params.update(body)
        except (json.JSONDecodeError, TypeError):
            logger.warning("Failed to parse request body as JSON")

    return params


def create_response(status_code, body, headers=None):
    """Create a standardized API Gateway response."""
    response = {
        'statusCode': status_code,
        'headers': {
            'Content-Type': 'application/json',
            'Access-Control-Allow-Origin': os.environ.get('ALLOWED_ORIGIN', '*'),
            'Access-Control-Allow-Methods': 'GET, POST, OPTIONS',
            'Access-Control-Allow-Headers': 'Content-Type, Authorization',
            'X-Content-Type-Options': 'nosniff',
            'X-Frame-Options': 'DENY',
            'Cache-Control': 'no-store',
        },
        'body': json.dumps(body, default=str),
    }
    if headers:
        response['headers'].update(headers)
    return response


def lambda_handler(event, context):
    """
    Main Lambda handler for product search API.
    
    Supports the following search parameters:
    - product_id: Exact match on product ID
    - name: Partial match (LIKE) on product name
    - category: Exact match on category
    - brand: Exact match on brand
    - sku: Exact match on SKU
    - status: Exact match on status (e.g., 'active', 'inactive')
    - description: Partial match (LIKE) on description
    - min_price / max_price: Price range filter
    - min_rating / max_rating: Rating range filter
    - sort_by: Column to sort by (default: product_id)
    - sort_dir: Sort direction - ASC or DESC (default: ASC)
    - limit: Number of results (default: 20, max: 100)
    - offset: Pagination offset (default: 0)
    """
    logger.info("Product search request received")

    # Handle CORS preflight
    if event.get('httpMethod') == 'OPTIONS':
        return create_response(200, {'message': 'OK'})

    connection = None

    try:
        # Extract and validate parameters
        params = extract_params(event)
        logger.info(f"Search parameters: {json.dumps({k: v for k, v in params.items() if k in ALLOWED_SEARCH_FIELDS or k in ('sort_by', 'sort_dir', 'limit', 'offset')})}")

        # Build queries
        search_query, search_values = build_search_query(params)
        count_query, count_values = build_count_query(params)

        logger.info(f"Executing search query: {search_query}")

        # Connect to database
        connection = get_db_connection()

        with connection.cursor() as cursor:
            # Execute count query for pagination metadata
            cursor.execute(count_query, count_values)
            count_result = cursor.fetchone()
            total_count = count_result['total'] if count_result else 0

            # Execute search query
            cursor.execute(search_query, search_values)
            products = cursor.fetchall()

        # Calculate pagination metadata
        try:
            limit = int(params.get('limit', DEFAULT_LIMIT))
            limit = max(1, min(limit, MAX_LIMIT))
        except (ValueError, TypeError):
            limit = DEFAULT_LIMIT

        try:
            offset = int(params.get('offset', 0))
            offset = max(0, offset)
        except (ValueError, TypeError):
            offset = 0

        total_pages = (total_count + limit - 1) // limit if limit > 0 else 0
        current_page = (offset // limit) + 1 if limit > 0 else 1

        response_body = {
            'success': True,
            'data': {
                'products': products,
                'pagination': {
                    'total_count': total_count,
                    'limit': limit,
                    'offset': offset,
                    'total_pages': total_pages,
                    'current_page': current_page,
                    'has_next': offset + limit < total_count,
                    'has_previous': offset > 0,
                },
            },
        }

        logger.info(f"Search completed: {len(products)} products found out of {total_count} total")
        return create_response(200, response_body)

    except pymysql.MySQLError as e:
        logger.error(f"Database error: {str(e)}")
        return create_response(500, {
            'success': False,
            'error': 'An internal database error occurred. Please try again later.',
        })

    except json.JSONDecodeError as e:
        logger.error(f"JSON parsing error: {str(e)}")
        return create_response(400, {
            'success': False,
            'error': 'Invalid JSON in request body.',
        })

    except Exception as e:
        logger.error(f"Unexpected error: {str(e)}", exc_info=True)
        return create_response(500, {
            'success': False,
            'error': 'An unexpected error occurred. Please try again later.',
        })

    finally:
        if connection:
            try:
                connection.close()
            except Exception:
                logger.warning("Failed to close database connection")